#include <bits/stdc++.h>
using namespace std;
int n,x,ans=0,w[1003],v[1003];
long long dp[1003];
int main(){
    cin>>n>>x;
    for(int i=1;i<=n;i++){
        int a,b,c;
        cin>>a>>b>>c;
        w[i]=c,v[i]=b-a,ans+=a;
    }
    for(int i=1;i<=n;i++)
        for(int j=x;j>=0;j--)
            if(j>=w[i])
                dp[j]=max(dp[j],dp[j-w[i]]+v[i]);
    cout<<(dp[x]+ans)*5;
    return 0;
}
